import React from "react";
const Tachometer = ({ rpm, maxRpm }) => {
    const width = 250; // Размер тахометра
    const height = 250;
    const centerX = width / 2;
    const centerY = height / 2;
    const outerRadius = Math.min(width, height) / 2 - 10;
    const innerRadius = outerRadius - 50; // Размер внутреннего круга
    // Угол смещения для распределения отметок
    const segments = 8; // Всего сегментов
    const segmentAngle = (2 * Math.PI) / (segments + 1); // Интервалы для "0–7" с дополнительным пустым интервалом
    // Расчет угла поворота стрелки
    const calculateRotation = (rpm) => {
        const percentage = Math.min(rpm / maxRpm, 1); // Ограничиваем значение до 1 (100%)
        return Math.PI / 2 + percentage * (7 * segmentAngle); // Учитываем только сегменты "0–7"
    };
    const needleAngle = calculateRotation(rpm);
    // Координаты для треугольной стрелки
    const arrowLength = outerRadius - 8; // Длина стрелки чуть меньше радиуса
    const arrowWidth = 20; // Ширина основания стрелки
    const tipX = centerX + Math.cos(needleAngle) * arrowLength;
    const tipY = centerY + Math.sin(needleAngle) * arrowLength;
    const baseLeftX = centerX + Math.cos(needleAngle + Math.PI / 2) * (arrowWidth / 2);
    const baseLeftY = centerY + Math.sin(needleAngle + Math.PI / 2) * (arrowWidth / 2);
    const baseRightX = centerX + Math.cos(needleAngle - Math.PI / 2) * (arrowWidth / 2);
    const baseRightY = centerY + Math.sin(needleAngle - Math.PI / 2) * (arrowWidth / 2);
    // Углы для красного отрезка (от 6 до 7)
    const redStartAngle = Math.PI / 2 + 6 * segmentAngle;
    const redEndAngle = Math.PI / 2 + 7 * segmentAngle;
    // Радиус красного отрезка чуть ближе к краю
    const redRadius = outerRadius - 3;
    const redArcX1 = centerX + Math.cos(redStartAngle) * redRadius;
    const redArcY1 = centerY + Math.sin(redStartAngle) * redRadius;
    const redArcX2 = centerX + Math.cos(redEndAngle) * redRadius;
    const redArcY2 = centerY + Math.sin(redEndAngle) * redRadius;
    const largeArcFlag = redEndAngle - redStartAngle <= Math.PI ? "0" : "1";
    return (React.createElement("svg", { width: width, height: height },
        React.createElement("circle", { cx: centerX, cy: centerY, r: outerRadius, fill: "#222", stroke: "#555", strokeWidth: 6 }),
        React.createElement("path", { d: `M ${redArcX1} ${redArcY1} A ${redRadius} ${redRadius} 0 ${largeArcFlag} 1 ${redArcX2} ${redArcY2}`, fill: "none", stroke: "red", strokeWidth: 6 }),
        React.createElement("polygon", { points: `${tipX},${tipY} ${baseLeftX},${baseLeftY} ${baseRightX},${baseRightY}`, fill: "red" }),
        Array.from({ length: segments + 1 }).map((_, i) => {
            const angle = Math.PI / 2 + i * segmentAngle; // Смещение углов с интервалом
            const markX1 = centerX + Math.cos(angle) * (outerRadius - 10);
            const markY1 = centerY + Math.sin(angle) * (outerRadius - 10);
            const markX2 = centerX + Math.cos(angle) * outerRadius;
            const markY2 = centerY + Math.sin(angle) * outerRadius;
            const numberX = centerX + Math.cos(angle) * (outerRadius - 25);
            const numberY = centerY + Math.sin(angle) * (outerRadius - 25);
            return (React.createElement("g", { key: i },
                i !== segments && (React.createElement("line", { x1: markX1, y1: markY1, x2: markX2, y2: markY2, stroke: i === segments ? "transparent" : "#FFF", strokeWidth: 2 })),
                i !== 0 && i !== segments && (React.createElement("text", { x: numberX, y: numberY, fill: "#FFF", fontSize: "16", fontWeight: "bold", textAnchor: "middle", alignmentBaseline: "middle" }, i))));
        }),
        React.createElement("circle", { cx: centerX, cy: centerY, r: innerRadius, fill: "#000" }),
        React.createElement("text", { x: centerX, y: centerY + 5, fill: "#FFF", fontSize: "16", fontWeight: "bold", textAnchor: "middle", alignmentBaseline: "middle" }, "x1000rpm")));
};
export default Tachometer;
